// ============================================================
// Process one chunk of grants: AI classify, insert eligible,
// fire-and-forget screener webhook.
// Input: { org_id, org, nicheSummary, callbackUrl, chunk_index, total_chunks, grants }
// ============================================================

const raw = $input.first().json;
const input = raw.body || raw;
const orgId = input.org_id;
const org = input.org || { id: orgId };
const nicheSummary = input.nicheSummary || '';
const callbackUrl = input.callbackUrl;
const chunkIndex = input.chunk_index || 0;
const totalChunks = input.total_chunks || 1;
const grants = Array.isArray(input.grants) ? input.grants : [];

if (grants.length === 0) {
  return [{ json: { success: true, chunk_index: chunkIndex, inserted: 0, screened: 0, total: 0 } }];
}

const BATCH_SIZE = 40;
const openAiKey = 'REPLACE_ME';

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';
const supaHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
};
const webhookHeaders = {
  'Content-Type': 'application/json',
  'x-webhook-secret': 't+KHcyHWsievwSbCyHvDJk5/YbZayMsiKp0letIw0Xk='
};

async function sendStatus(status, stage_message) {
  if (!callbackUrl || !orgId) return;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: callbackUrl,
      headers: webhookHeaders,
      body: { org_id: orgId, status, stage_message }
    });
  } catch(e) {}
}

const systemPrompt = `You are a grant eligibility and classification assistant. Given a grant, an organization with its location, and the organization's narratives (which describe its mission, programs, and focus areas), first classify the grant type, then determine if the organization is eligible by location, then evaluate niche alignment.

STEP 1 - CLASSIFY THE GRANT TYPE:
- Federal: Funded by federal agencies (HHS, SAMHSA, ACF, DOL, ED, HUD, USDA, etc.) or listed on Grants.gov. grant_state = null.
- State grants: The organization is ONLY eligible if it operates in, is headquartered in, or serves communities in the grant's state.
- Philanthropic: From private foundations, trusts, corporate giving programs, or nonprofits. grant_state = null.

STEP 2 - DETERMINE LOCATION ELIGIBILITY:
- Federal grants: eligible.
- Philanthropic grants: eligible.
- State grants: only eligible if the org is located in or serves that state. If the org has no location data, mark eligible.

STEP 3 - EVALUATE NICHE ALIGNMENT (STRICT):
Mark niche_aligned = true ONLY if the grant directly funds work in one of the org's stated program areas, populations, or sectors. Broad themes alone are not sufficient. When in doubt, mark false. If no narratives, mark false.

The grant must pass BOTH location eligibility AND niche alignment to be marked eligible.

Return ONLY valid JSON - an array with one object per grant in the same order, each with:
{
  "grant_type": "federal" or "state" or "philanthropic",
  "grant_state": "Full state name if state grant, otherwise null",
  "location_eligible": true or false,
  "niche_aligned": true or false,
  "eligible": true or false,
  "reason": "brief explanation"
}`;

const totalBatches = Math.ceil(grants.length / BATCH_SIZE);
let totalInserted = 0;
let totalScreened = 0;
let newInserts = 0;
let alreadyExisted = 0;

for (let b = 0; b < totalBatches; b++) {
  const start = b * BATCH_SIZE;
  const batch = grants.slice(start, start + BATCH_SIZE);

  await sendStatus.call(this, 'filtering', 'Matching grants (chunk ' + (chunkIndex + 1) + '/' + totalChunks + ') - batch ' + (b + 1) + '/' + totalBatches);

  const userPrompt = `
Organization:
- ID: ${org.id}
- Location: ${org.geographic_focus ? (Array.isArray(org.geographic_focus) ? org.geographic_focus.join(', ') : org.geographic_focus) : 'Not set'}
- Address: ${org.address || 'Not set'}

Organization Narratives (niche/focus context):
${nicheSummary || 'No narratives available'}

Evaluate EACH grant below against the organization above. For each grant, classify its type, determine location eligibility, and evaluate niche alignment.

Grants:
${JSON.stringify(batch, null, 2)}`;

  let parsedResults = [];
  try {
    const aiResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: {
        'Authorization': 'Bearer ' + openAiKey,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model: 'gpt-4.1-mini',
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt }
        ],
        temperature: 0,
      }),
    });

    const aiText = aiResponse.choices?.[0]?.message?.content || '[]';
    const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(cleaned);
    parsedResults = Array.isArray(parsed) ? parsed : [parsed];
  } catch(e) {
    parsedResults = batch.map(() => ({
      grant_type: 'federal', grant_state: null,
      location_eligible: true, niche_aligned: true,
      eligible: true, reason: 'AI parse failed, defaulting to eligible'
    }));
  }

  const toInsert = [];
  batch.forEach((grant, index) => {
    const parsed = parsedResults[index] || parsedResults[0] || {
      grant_type: 'federal', grant_state: null,
      location_eligible: true, niche_aligned: true,
      eligible: true, reason: 'No AI result'
    };
    if (parsed.eligible === false) return;

    const description = grant.description || '';
    const descriptionHtml = '<div><h3>Grant Opportunity</h3>' +
      '<p><strong>Source:</strong> ' + (grant.source || '') + '</p>' +
      '<p><strong>Agency:</strong> ' + (grant.agency || '') + '</p>' +
      '<p><strong>Type:</strong> ' + (parsed.grant_type || 'unknown') + '</p>' +
      (parsed.grant_state ? '<p><strong>State:</strong> ' + parsed.grant_state + '</p>' : '') +
      '<p><strong>Award Range:</strong> $' + (grant.awardFloor || 0) + ' - $' + (grant.awardCeiling || 0) + '</p>' +
      '<p><strong>Open Date:</strong> ' + (grant.openDate || '') + '</p>' +
      '<p><strong>Deadline:</strong> ' + (grant.closeDate || '') + '</p>' +
      '<hr><h4>Description:</h4>' +
      '<p>' + description + '</p>' +
      '<p><em>Location Filter: ' + (parsed.reason || 'N/A') + '</em></p>' +
      '<hr>' +
      '<p><a href="' + (grant.source_url || grant.link || '') + '">View Original Listing</a></p>' +
      '</div>';

    let deadlineValue = null;
    if (grant.closeDate && grant.closeDate !== 'See listing' && grant.closeDate !== 'Not specified' && grant.closeDate !== 'Rolling') {
      const d = new Date(grant.closeDate);
      if (!isNaN(d.getTime())) {
        const yyyy = d.getUTCFullYear();
        const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
        const dd = String(d.getUTCDate()).padStart(2, '0');
        deadlineValue = yyyy + '-' + mm + '-' + dd + 'T00:00:00.000Z';
      } else {
        deadlineValue = grant.closeDate;
      }
    }

    toInsert.push({
      org_id: org.id,
      title: grant.title || '',
      funder_name: grant.agency || null,
      description: description,
      amount: grant.awardCeiling > 0 ? grant.awardCeiling : null,
      deadline: deadlineValue,
      stage: 'discovery',
      source: grant.source || 'Grant Scanner',
      source_id: grant.source_id || grant.oppNum,
      source_url: grant.source_url || grant.link,
      metadata: {
        grants_gov_id: grant.id,
        agency_code: grant.agencyCode,
        open_date: grant.openDate,
        award_floor: grant.awardFloor,
        award_ceiling: grant.awardCeiling,
        grant_type: parsed.grant_type || 'unknown',
        grant_state: parsed.grant_state || null,
        location_filter_reason: parsed.reason || '',
        location_eligible: parsed.location_eligible !== false,
        niche_aligned: parsed.niche_aligned !== false,
        priority: 'medium',
        description_html: descriptionHtml
      }
    });
  });

  if (toInsert.length > 0) {
    await Promise.all(toInsert.map(async (grant) => {
      try {
        const insertedRows = await this.helpers.httpRequest({
          method: 'POST',
          url: supabaseUrl + '/grants?on_conflict=org_id,source_id',
          headers: {
            ...supaHeaders,
            'Prefer': 'return=representation,resolution=ignore-duplicates',
          },
          body: JSON.stringify(grant),
        });
        if (Array.isArray(insertedRows) && insertedRows.length > 0) {
          grant._dbId = insertedRows[0].id;
          grant._status = 'new';
          newInserts++;
        } else {
          const existing = await this.helpers.httpRequest({
            method: 'GET',
            url: supabaseUrl + '/grants?org_id=eq.' + encodeURIComponent(grant.org_id) + '&source_id=eq.' + encodeURIComponent(grant.source_id) + '&select=id&limit=1',
            headers: supaHeaders,
          });
          if (Array.isArray(existing) && existing.length > 0) {
            grant._dbId = existing[0].id;
          }
          grant._status = 'existing';
          alreadyExisted++;
        }
        totalInserted++;
      } catch(e) { grant._status = 'error'; }
    }));
  }

  const screenerCalls = toInsert.filter(g => g._dbId).map(g => this.helpers.httpRequest({
    method: 'POST',
    url: 'https://n8n.thebrownmine.com/webhook/screen-grant',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      url: g.source_url || '',
      grantid: g._dbId,
      orgId: g.org_id || '',
      grantData: {
        title: g.title || '',
        agency: g.funder_name || '',
        awardRange: g.amount ? String(g.amount) : 'Not specified',
        deadline: g.deadline || '',
        description: g.description || '',
        source: g.source || '',
        org_id: g.org_id || ''
      }
    }),
    timeout: 5000,
  }));
  const screenerResults = await Promise.allSettled(screenerCalls);
  totalScreened += screenerResults.filter(r => r.status === 'fulfilled').length;
}

return [{ json: { success: true, chunk_index: chunkIndex, total_chunks: totalChunks, total: grants.length, inserted: totalInserted, new: newInserts, existing: alreadyExisted, screened: totalScreened } }];
